import anthropic

client = anthropic.Anthropic()

# Upload PDF
uploaded = client.beta.files.upload(
    file=(
        "research_paper.pdf",
        open("research_paper.pdf", "rb"),
        "application/pdf"
    )
)

# Reference in Q&A
response = client.beta.messages.create(
    model="claude-opus-4-8",
    max_tokens=16000,
    messages=[{
        "role": "user",
        "content": [
            {"type": "text", "text": "Summarize the methodology"},
            {
                "type": "document",
                "source": {"type": "file", "file_id": uploaded.id}
            }
        ]
    }]
)

# Split 500-page document into 5 × 100-page chunks
chunks = split_pdf_into_chunks("paper.pdf", chunk_size=100)

# Upload each chunk
for i, chunk in enumerate(chunks):
    uploaded = client.beta.files.upload(
        file=(f"chunk_{i}.pdf", chunk, "application/pdf")
    )
    file_ids.append(uploaded.id)

# Process all chunks together
response = client.messages.create(
    messages=[{
        "content": [
            {"type": "text", "text": "Summarize the entire paper"},
            {"type": "document", "source": {"type": "file", "file_id": file_ids[0]}},
            {"type": "document", "source": {"type": "file", "file_id": file_ids [devpost](https://devpost.com/software/docuask-an-ai-powered-document-q-a-assistant)}},
            # ... all chunks
        ]
    }]
)

# Upload multiple research papers
papers = []
for paper_file in ["paper1.pdf", "paper2.pdf", "paper3.pdf"]:
    uploaded = client.beta.files.upload(
        file=(paper_file, open(paper_file, "rb"), "application/pdf")
    )
    papers.append(uploaded.id)

# Ask cross-document questions
response = client.beta.messages.create(
    model="claude-opus-4-8",
    messages=[{
        "role": "user",
        "content": [
            {"type": "text", "text": "Compare the methodologies across all three papers"},
            {"type": "document", "source": {"type": "file", "file_id": papers[0]}},
            {"type": "document", "source": {"type": "file", "file_id": papers [devpost](https://devpost.com/software/docuask-an-ai-powered-document-q-a-assistant)}},
            {"type": "document", "source": {"type": "file", "file_id": papers [meteoraweb](https://meteoraweb.com/en/intelligenza-artificiale/claude-for-long-form-writing-and-document-analysis-a-practical-guide)}}
        ]
    }]
)
